$root = (Get-Location).Path
foreach ($zip in @(Get-ChildItem -File -Filter *.zip)) {
    $name = $zip.BaseName
    $dest = Join-Path $root $name
    try {
        $ErrorActionPreference = 'Stop'
        if (Test-Path -LiteralPath $dest) { Remove-Item -LiteralPath $dest -Recurse -Force }
        New-Item -ItemType Directory -Path $dest | Out-Null
        Expand-Archive -LiteralPath $zip.FullName -DestinationPath $dest -Force
        $scan = Get-ChildItem -LiteralPath $dest -Recurse -File |
            Where-Object { $_.Extension -in '.nessus', '.xml' } | Select-Object -First 1
        if (-not $scan) { throw "No .nessus/.xml found inside $($zip.Name)" }
        $target = Join-Path $dest ($name + '.nessus')
        if ($scan.FullName -ne $target) { Move-Item -LiteralPath $scan.FullName -Destination $target -Force }
        Copy-Item -LiteralPath $target -Destination (Join-Path $root ($name + '.nessus')) -Force
        Remove-Item -LiteralPath $zip.FullName -Force
        Write-Host "OK   $name"
    } catch {
        Write-Host "FAIL $name -> $($_.Exception.Message)" -ForegroundColor Red
    }
}
